import React, { useState } from "react";
import { useTranslation } from "react-i18next";
import {
  Table,
  Card,
  Typography,
  Space,
  Button,
  Input,
  theme,
  Modal,
  Tag,
  Divider,
  Flex,
  DatePicker,
  message
} from "antd";
import {
  SearchOutlined,
  PrinterOutlined,
  DownloadOutlined,
  FileSearchOutlined,
  FilterOutlined,
  CloseOutlined,
  FileExcelOutlined,
  CheckOutlined,
  CalendarOutlined,
  UserOutlined as AntUserOutlined
} from "@ant-design/icons";
import { QUARANTINE_DB } from "../../../mocks/db";
import ExcelJS from "exceljs";

const { Title, Text } = Typography;
const { RangePicker } = DatePicker;

const DailyReportPage: React.FC = () => {
  const { t } = useTranslation(["quarantine", "report", "common"]);
  const { token } = theme.useToken();
  const [isReportModalOpen, setIsReportModalOpen] = useState(false);
  const [selectedReport, setSelectedReport] = useState<any>(null);

  const handleDownloadExcel = async (report?: any) => {
    try {
      const workbook = new ExcelJS.Workbook();
      const worksheet = workbook.addWorksheet("DailyQuarantineReport");

      // Define Table Columns
      worksheet.columns = [
        { header: t("report:daily.columns.id"), key: "id", width: 25 },
        { header: t("report:daily.columns.date"), key: "date", width: 15 },
        { header: t("report:daily.columns.reportTitle"), key: "title", width: 40 },
        { header: t("report:daily.columns.department"), key: "department", width: 20 },
        { header: t("report:daily.columns.author"), key: "author", width: 15 },
        { header: t("report:daily.columns.status"), key: "status", width: 15 }
      ];

      // Styling Headers
      worksheet.getRow(1).font = { bold: true };
      worksheet.getRow(1).fill = { type: 'pattern', pattern: 'solid', fgColor: { argb: 'FFE6F7FF' } };

      // Add Data
      const sourceData = report ? [report] : QUARANTINE_DB.dailyReports;
      sourceData.forEach(item => {
        worksheet.addRow({
          id: item.id,
          date: item.date,
          title: item.title,
          department: item.department,
          author: item.author,
          status: item.status
        });
      });

      // Write to buffer and trigger download
      const buffer = await workbook.xlsx.writeBuffer();
      const blob = new Blob([buffer], { type: "application/vnd.openxmlformats-officedocument.spreadsheetml.sheet" });
      const url = window.URL.createObjectURL(blob);
      const anchor = document.createElement("a");
      anchor.href = url;
      anchor.download = `Quarantine_Report_${report ? report.id : dayjs().format("YYYYMMDD")}.xlsx`;
      anchor.click();
      window.URL.revokeObjectURL(url);
      
      message.success(t("quarantine:navigation.reportGenerated"));
    } catch (error) {
      console.error("Excel download error:", error);
      message.error("Failed to generate Excel file.");
    }
  };

  const handlePrint = (report: any) => {
    setSelectedReport(report);
    setIsReportModalOpen(true);
    // Give a small delay for the modal/report to render before printing
    setTimeout(() => {
      window.print();
    }, 500);
  };

  const columns = [
    {
      title: t("report:daily.columns.id"),
      dataIndex: "id",
      key: "id",
      width: 150,
      render: (t: string) => <Text style={{ color: token.colorTextQuaternary, fontSize: 12, fontFamily: "monospace" }}>{t}</Text>
    },
    {
      title: t("report:daily.columns.date"),
      dataIndex: "date",
      key: "date",
      width: 140,
      render: (t: string) => <Space size={4}><CalendarOutlined style={{ color: token.colorPrimary, fontSize: 12 }} /><Text style={{ fontSize: 13 }}>{t}</Text></Space>
    },
    {
      title: t("report:daily.columns.reportTitle"),
      dataIndex: "title",
      key: "title",
      align: "left" as const,
      render: (t: string) => <Text strong style={{ color: token.colorText }}>{t}</Text>
    },
    {
      title: t("report:daily.columns.department"),
      dataIndex: "department",
      key: "department",
      width: 150,
      render: (t: string) => <Tag color="blue" variant="filled" style={{ borderRadius: 4 }}>{t}</Tag>
    },
    {
      title: t("report:daily.columns.author"),
      dataIndex: "author",
      key: "author",
      width: 120,
      render: (t: string) => <Space size={4}><AntUserOutlined style={{ color: token.colorTextQuaternary }} /><Text style={{ fontSize: 13 }}>{t}</Text></Space>
    },
    {
      title: t("report:daily.columns.view"),
      key: "view",
      align: "center" as const,
      width: 100,
      render: (_: any, record: any) => (
        <Button 
          type="link" 
          icon={<FileSearchOutlined />} 
          style={{ color: token.colorPrimary, fontWeight: "bold" }}
          onClick={() => {
            setSelectedReport(record);
            setIsReportModalOpen(true);
          }}
        >
          VIEW
        </Button>
      )
    },
    {
      title: t("report:daily.columns.print"),
      key: "print",
      align: "center" as const,
      width: 80,
      render: (_: any, record: any) => (
        <Button 
          type="text" 
          icon={<PrinterOutlined />} 
          style={{ color: token.colorTextQuaternary }}
          onClick={() => handlePrint(record)}
        />
      )
    },
    {
      title: t("report:daily.columns.download"),
      key: "download",
      align: "center" as const,
      width: 110,
      render: (_: any, record: any) => (
        <Button 
          type="text" 
          icon={<FileExcelOutlined />} 
          style={{ color: token.colorSuccess }}
          onClick={() => handleDownloadExcel(record)}
        />
      )
    }
  ];

  return (
    <div className="p-8 h-full flex flex-col" style={{ background: token.colorBgLayout }}>
      {/* Header & Filter Section */}
      <div className="flex flex-col gap-6 mb-8">
        <Flex justify="space-between" align="center">
          <Title level={3} style={{ margin: 0, color: token.colorText, fontWeight: "bold", letterSpacing: -0.5 }}>
            {t("report:daily.title")}
          </Title>
          <Button 
            className="btn-vibrant-primary h-11 px-8"
            icon={<FilterOutlined />}
          >
            {t("quarantine:common.search")}
          </Button>
        </Flex>

        <Card 
          bordered={false} 
          style={{ background: token.colorBgContainer, borderRadius: 12 }} 
          styles={{ body: { padding: "16px 24px" } }}
        >
          <Flex gap={24} align="center">
            <Flex vertical gap={4} flex={1}>
              <Text type="secondary" style={{ fontSize: 12, fontWeight: "bold" }}>{t("report:daily.columns.date")}</Text>
              <RangePicker style={{ height: 40, width: "100%", background: token.colorFillAlter, border: "none", borderRadius: 6 }} />
            </Flex>
            <Flex vertical gap={4} flex={1}>
              <Text type="secondary" style={{ fontSize: 12, fontWeight: "bold" }}>{t("report:daily.columns.author")}</Text>
              <Input 
                placeholder={t("quarantine:searchPlaceholder")} 
                style={{ height: 40, background: token.colorFillAlter, border: "none", borderRadius: 6 }} 
              />
            </Flex>
            <Flex vertical gap={4} flex={2}>
              <Text type="secondary" style={{ fontSize: 12, fontWeight: "bold" }}>{t("report:daily.columns.reportTitle")}</Text>
              <Input 
                placeholder={t("report:daily.columns.reportTitle")} 
                prefix={<SearchOutlined style={{ color: token.colorTextQuaternary }} />} 
                style={{ height: 40, background: token.colorFillAlter, border: "none", borderRadius: 6 }} 
              />
            </Flex>
          </Flex>
        </Card>
      </div>

      {/* Report List Table */}
      <Card 
        bordered={false} 
        className="shadow-sm flex-1 overflow-hidden"
        style={{ background: token.colorBgContainer, borderRadius: 16 }}
        styles={{ body: { padding: 0 } }}
      >
        <Table 
          columns={columns} 
          dataSource={QUARANTINE_DB.dailyReports.map((r, i) => ({ ...r, key: i }))} 
          pagination={{ pageSize: 12 }}
          scroll={{ x: 1000, y: 'calc(100vh - 300px)' }}
          className="custom-report-table"
        />
      </Card>

      {/* Report Form Modal (Precision Layout based on User Screenshot) */}
      <Modal
        title={<Text className="font-bold ml-2" style={{ color: token.colorText, fontSize: 18 }}>{t("report:daily.form.mainTitle")}</Text>}
        open={isReportModalOpen}
        onCancel={() => setIsReportModalOpen(false)}
        footer={(
          <Flex justify="end" gap={12} className="p-6 pt-0 no-print">
             <Button icon={<PrinterOutlined />} className="btn-vibrant-secondary h-11 px-6" onClick={() => handlePrint(selectedReport)}>
                {t("quarantine:common.print")}
             </Button>
             <Button icon={<DownloadOutlined />} className="btn-vibrant-secondary h-11 px-6" onClick={() => handleDownloadExcel(selectedReport)}>
                {t("quarantine:common.download")}
             </Button>
             <Button className="btn-vibrant-primary h-11 px-10" onClick={() => setIsReportModalOpen(false)}>
                {t("quarantine:common.confirm")}
             </Button>
          </Flex>
        )}
        centered
        width={900}
        styles={{ 
          mask: { backdropFilter: "blur(12px)" }, 
          body: { padding: 0 }, // Body padding moved to container for better scrolling
          header: { padding: "24px 24px 0", marginBottom: 0 }
        }}
        closeIcon={<CloseOutlined style={{ color: token.colorTextQuaternary }} />}
      >
        {selectedReport && (
          <div className="report-container-scroll animate-in fade-in zoom-in-95 duration-500">
             <div className="p-10">
             {/* Report Header Info */}
             <Flex justify="end" vertical className="mb-6 text-right">
                <Space><Text style={{ color: token.colorTextSecondary }}>{t("report:daily.form.dept")} :</Text> <Text strong>{selectedReport.department}</Text></Space>
                <Space><Text style={{ color: token.colorTextSecondary }}>{t("report:daily.form.author")} :</Text> <Text strong>{selectedReport.author}</Text></Space>
                <Space><Text style={{ color: token.colorTextSecondary }}>{t("report:daily.form.date")} :</Text> <Text strong>20{selectedReport.date.replace(/-/g, '. ')}</Text></Space>
             </Flex>

             <Title level={2} className="text-center mb-10 tracking-[10px]" style={{ color: token.colorText }}>
                {t("report:daily.form.mainTitle").toUpperCase()}
             </Title>

             <div className="report-form-table">
                {/* Section 1: Quarantine Inspection List */}
                <div className="section-header">{t("report:daily.form.section1.title")}</div>
                <table className="inner-table">
                   <thead>
                      <tr>
                         <th rowSpan={2}>{t("report:daily.form.section1.date")}</th>
                         <th colSpan={3}>{t("report:daily.form.section1.visitor")}</th>
                         <th rowSpan={2}>{t("report:daily.form.section1.agent")}</th>
                         <th rowSpan={2}>{t("report:daily.form.section1.confirm")}</th>
                         <th rowSpan={2}>{t("report:daily.form.section1.note")}</th>
                      </tr>
                      <tr>
                         <th>{t("report:daily.form.section1.visName")}</th>
                         <th>{t("report:daily.form.section1.visLoc")}</th>
                         <th>{t("report:daily.form.section1.visContact")}</th>
                      </tr>
                   </thead>
                   <tbody>
                      {selectedReport.quarantineList.map((item: any, i: number) => (
                         <tr key={i}>
                            <td>{item.date}</td>
                            <td>{item.name}</td>
                            <td>{item.location}</td>
                            <td>{item.contact}</td>
                            <td>{item.agent}</td>
                            <td className="text-center">
                               <CheckOutlined style={{ color: token.colorSuccess, fontSize: 12 }} />
                            </td>
                            <td>{item.note}</td>
                         </tr>
                      ))}
                      {/* Empty rows to match style */}
                      {[1, 2].map((_, i) => (
                         <tr key={`empty-${i}`}><td className="h-8"></td><td></td><td></td><td></td><td></td><td></td><td></td></tr>
                      ))}
                   </tbody>
                </table>

                <Divider className="my-8" />

                {/* Section 2: Pest Monitoring */}
                <div className="section-header">{t("report:daily.form.section2.title")}</div>
                <table className="inner-table">
                   <thead>
                      <tr>
                         <th>{t("report:daily.form.section2.date")}</th>
                         <th>{t("report:daily.form.section2.agent")}</th>
                         <th className="bg-blue-900/10" style={{ background: `${token.colorPrimary}1a` }}>{t("report:daily.form.section2.visitor")}</th>
                         <th>{t("report:daily.form.section2.visName")}</th>
                         <th>{t("report:daily.form.section2.visLoc")}</th>
                         <th>{t("report:daily.form.section2.visContact")}</th>
                      </tr>
                   </thead>
                   <tbody>
                      {selectedReport.pestMonitoring.length > 0 ? selectedReport.pestMonitoring.map((item: any, i: number) => (
                         <tr key={i}>
                            <td>{item.date}</td>
                            <td>{item.agent}</td>
                            <td>방문고객</td>
                            <td>{item.customerName}</td>
                            <td>{item.location}</td>
                            <td>{item.contact}</td>
                         </tr>
                      )) : (
                         <tr><td className="h-8"></td><td></td><td></td><td></td><td></td><td></td></tr>
                      )}
                   </tbody>
                </table>

                {/* Section 3: Photo areas */}
                <div className="grid grid-cols-2 gap-0 border-t border-x border-b border-[#ffffff1a] mt-8" style={{ borderColor: token.colorBorderSecondary }}>
                   <div className="flex flex-col border-r" style={{ borderColor: token.colorBorderSecondary }}>
                      <div className="p-2 text-center text-xs font-bold bg-[#ffffff0a]" style={{ background: token.colorFillAlter }}>{t("report:daily.form.section3.title1")}</div>
                      <div className="h-48 flex items-center justify-center text-xs text-gray-500 italic">No image file</div>
                   </div>
                   <div className="flex flex-col">
                      <div className="p-2 text-center text-xs font-bold bg-[#ffffff0a]" style={{ background: token.colorFillAlter }}>{t("report:daily.form.section3.title2")}</div>
                      <div className="h-48 flex items-center justify-center text-xs text-gray-500 italic">Work completed successfully</div>
                   </div>
                </div>

                {/* Footer labels */}
                <div className="mt-8 border" style={{ borderColor: token.colorBorderSecondary }}>
                   <div className="flex border-b" style={{ borderColor: token.colorBorderSecondary }}>
                      <div className="w-48 p-3 text-xs font-bold flex items-center bg-[#ffffff0a]" style={{ background: token.colorFillAlter }}>{t("report:daily.form.footer.pestAnalysis")}</div>
                      <div className="flex-1 p-3 text-xs">{selectedReport.pestAnalysis}</div>
                   </div>
                   <div className="flex border-b" style={{ borderColor: token.colorBorderSecondary }}>
                      <div className="w-48 p-3 text-xs font-bold flex items-center bg-[#ffffff0a]" style={{ background: token.colorFillAlter }}>{t("report:daily.form.footer.usedDrugs")}</div>
                      <div className="flex-1 p-3 text-xs">{selectedReport.usedDrugs}</div>
                   </div>
                   <div className="flex">
                      <div className="w-48 p-3 text-xs font-bold flex items-center bg-[#ffffff0a]" style={{ background: token.colorFillAlter }}>{t("report:daily.form.footer.methods")}</div>
                      <div className="flex-1 p-3 text-xs">{selectedReport.methods}</div>
                   </div>
                </div>
             </div>

             <Divider className="my-8" />
             <Text italic type="secondary" style={{ fontSize: 11 }}>* {t("report:daily.form.footer.systemLog")}</Text>
             </div>
          </div>
        )}
      </Modal>

      <style>{`
        .custom-report-table .ant-table { background: transparent !important; }
        .custom-report-table .ant-table-thead > tr > th { 
          background: ${token.colorFillAlter} !important; 
          color: ${token.colorTextDescription} !important; 
          font-size: 13px !important; 
          font-weight: bold !important;
          border-bottom: 2px solid ${token.colorBorderSecondary} !important;
          text-align: center !important;
        }
        .custom-report-table .ant-table-tbody > tr > td { 
           border-bottom: 1px solid ${token.colorBorderSecondary} !important; 
           padding: 16px !important;
           text-align: center !important;
        }

        /* Report Form Table Styles */
        .report-container-scroll { 
           max-height: calc(100vh - 280px); 
           overflow-y: auto;
           scrollbar-width: thin;
           scrollbar-color: ${token.colorPrimary}44 transparent;
        }
        .report-container-scroll::-webkit-scrollbar { width: 6px; }
        .report-container-scroll::-webkit-scrollbar-track { background: transparent; }
        .report-container-scroll::-webkit-scrollbar-thumb { 
           background: ${token.colorFillSecondary}; 
           border-radius: 10px; 
        }
        .report-container-scroll::-webkit-scrollbar-thumb:hover { background: ${token.colorPrimary}88; }

        .report-form-table { width: 100%; color: ${token.colorTextSecondary}; }

        /* Robust Print Style */
        @media print {
          /* Hide EVERYTHING in the background */
          #root,
          .ant-layout,
          .ant-layout-sider, 
          .ant-layout-header, 
          .ant-layout-footer,
          footer,
          .ant-card,
          .ant-modal-mask, 
          .ant-modal-footer, 
          .ant-modal-close,
          .no-print,
          .btn-vibrant-primary,
          .btn-vibrant-secondary,
          .ant-btn,
          button,
          .ant-float-btn,
          .ant-float-btn-group {
            display: none !important;
          }

          /* Explicitly show the modal portal */
          body > .ant-modal-root,
          .ant-modal-root,
          .ant-modal-wrap,
          .ant-modal,
          .ant-modal-content,
          .report-container-scroll,
          .report-container-scroll * {
            display: block !important;
            visibility: visible !important;
          }

          /* Reset Layout for Print */
          body, html {
            background: #fff !important;
            color: #000 !important;
            width: 100%;
            height: auto !important;
          }

          .ant-modal-root {
            position: static !important;
          }

          .ant-modal-wrap {
            position: static !important;
            overflow: visible !important;
          }

          .ant-modal {
            top: 0 !important;
            width: 100% !important;
            max-width: 100% !important;
            margin: 0 !important;
            padding: 0 !important;
          }

          .ant-modal-content {
            background: #fff !important;
            box-shadow: none !important;
            padding: 0 !important;
          }

          .report-container-scroll {
            max-height: none !important;
            overflow: visible !important;
            height: auto !important;
            background: #fff !important;
          }

          /* Force colors and borders for printing */
          .inner-table th, .inner-table td, .section-header {
            border: 1px solid #000 !important;
            color: #000 !important;
            -webkit-print-color-adjust: exact;
          }
          
          .section-header, .inner-table th {
            background-color: #f5f5f5 !important;
          }

          .report-form-table Title, .report-form-table Text {
            color: #000 !important;
          }
        }
        .section-header { 
           background: ${token.colorPrimary}22; 
           padding: 6px 12px; 
           font-size: 13px; 
           font-weight: bold; 
           text-align: center;
           border: 1px solid ${token.colorBorderSecondary};
           margin-bottom: -1px;
        }
        .inner-table { width: 100%; border-collapse: collapse; table-layout: fixed; }
        .inner-table th, .inner-table td { 
           border: 1px solid ${token.colorBorderSecondary}; 
           padding: 8px; 
           font-size: 11px;
           text-align: center;
        }
        .inner-table th { background: ${token.colorFillAlter}; color: ${token.colorText}; font-weight: bold; }
        
        /* Solid Button System */
        .btn-vibrant-primary, .btn-vibrant-secondary { 
          background: ${token.colorPrimary} !important; 
          border-color: ${token.colorPrimary} !important; 
          color: #fff !important; 
          font-weight: bold !important; 
          border-radius: 6px !important; 
          transition: all 0.2s cubic-bezier(0.175, 0.885, 0.32, 1.275);
        }
        .btn-vibrant-primary:hover { filter: brightness(1.1); transform: translateY(-1px); }
        .btn-vibrant-secondary {
           background: ${token.colorFillAlter} !important;
           border: 1px solid ${token.colorBorderSecondary} !important;
           color: ${token.colorTextDescription} !important;
        }

        @keyframes zoom-in { from { opacity: 0; transform: scale(0.95); } to { opacity: 1; transform: scale(1); } }
        .animate-in { animation: zoom-in 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275); }
      `}</style>
    </div>
  );
};

export default DailyReportPage;
